import './index.less'
import { useCallback, useEffect, useMemo, useState } from 'react'
import { useTranslation } from 'react-i18next'
import { useNavigate, useParams } from 'react-router-dom'
import { Badge, Button, Modal, Space, Spin } from '@arco-design/web-react'
import { IconArrowLeft, IconDown, IconUp } from '@arco-design/web-react/icon'
import { useRequest } from 'ahooks'
import classNames from 'classnames'
import { downloadFileByUrl } from '@common/service/apis/file'
import PageWrapper from '@common/components/PageWrapper'
import {
  approveSecurityPatrolRequest,
  getPatrolFindingCountRequest,
  getSecurityPatrolApproveDetailRequest,
  getSecurityPatrolDetailRequest,
  rejectSecurityPatrolRequest,
} from '@/service'
import { handelFieldNameShow } from '@/utils/tools.ts'
import type {
  PatrolApproveDetailResponse,
  PatrolDetailResponse,
  PatrolTabSummaryResponseItem,
  SecurityPatrolAnswer,
  SecurityPatrolAnswerDto,
  SecurityPatrolApprovalRecord,
  SecurityPatrolAttachment,
  SecurityPatrolFindingDto,
  SecurityPatrolFloorSummary,
  SecurityPatrolShift,
  SecurityPatrolStatus,
} from '@/types/securityPatrol'
import { renderEllipsisText } from '@common/components/EllipsisText'
import { PatrolFormSetupTypeEnum } from '@/constants/PatrolFormSetup.ts'
import NoData from '@common/components/NoData'
import ApprovalProgressCard from '@common/components/ApprovalProgressCard'
const classPrefix = 'security-patrol-detail'

const statusColorMap: Record<SecurityPatrolStatus, string> = {
  draft: '#86909C',
  underReview: '#FF7D00',
  approved: '#45AD5E',
  rejected: '#F5626C',
}

const SHIFT_CODE_TO_KEY: Record<number, SecurityPatrolShift> = {
  1: 'day',
  2: 'night',
}

const IS_SITUATION_TO_ANSWER: Record<number, SecurityPatrolAnswer> = {
  0: 'no',
  1: 'yes',
  2: 'na',
}

// selectFloor string key → { type, floor } for API
// keys: 'around' | 'inside-{0..8}' | 'parking-{9..11}'
const resolveTypeAndFloorCode = (
  key: string,
): { type: number; floor: number } => {
  if (key === 'around') return { type: PatrolFormSetupTypeEnum.Around, floor: -1 }
  if (key.startsWith('inside-'))
    return { type: PatrolFormSetupTypeEnum.Inside, floor: parseInt(key.slice(7)) }
  if (key.startsWith('parking-'))
    return { type: PatrolFormSetupTypeEnum.Parking, floor: parseInt(key.slice(8)) }
  return { type: PatrolFormSetupTypeEnum.Around, floor: -1 }
}

interface PatrolChecklistItemViewData {
  id: string
  itemId?: number | string
  itemName?: string
  itemNameAr?: string
  answer: SecurityPatrolAnswer
  findings?: SecurityPatrolFindingDto[]
}

interface PatrolChecklistCategoryViewData {
  id: string
  sectionId?: number | string
  sectionName?: string
  sectionNameAr?: string
  defaultOpen?: boolean
  items: PatrolChecklistItemViewData[]
}

interface PatrolDetailViewData {
  patrolId: number | string
  patrolDate?: string
  shift?: SecurityPatrolShift
  inspector?: number | string
  inspectorName?: string
  inspectorNameAr?: string
  // Reporter = contractor (backend doc: "reporter is always a contractor")
  contractorName?: string
  contractorNameAr?: string
  status: SecurityPatrolStatus
  code: string
  // 当前 tab+floor 的答案列表
  currentAnswers: SecurityPatrolAnswerDto[]
  // tab 汇总
  tabSummaries: PatrolTabSummaryResponseItem[]
  // 楼层汇总（按 type+floorCode 索引）
  floorSummaries: SecurityPatrolFloorSummary[]
}

interface PreviewImage {
  url: string
  fileName?: string
}

const safeFieldText = (name?: string | null, nameAr?: string | null) =>
  handelFieldNameShow(name || '', nameAr || '') || '-'

const formatDisplayDate = (value?: string | null) => {
  if (!value) return '-'
  const datePart = value.split('T')[0]
  const [year, month, day] = datePart.split('-')
  return year && month && day ? `${day}/${month}/${year}` : value
}

const mapDetailResponse = (
  resp: PatrolDetailResponse,
  statusFallback: SecurityPatrolStatus,
  summaries?: PatrolTabSummaryResponseItem[],
): PatrolDetailViewData => {
  const tabSummaries = summaries || []
  const floorSummaries: SecurityPatrolFloorSummary[] = []
  tabSummaries.forEach((tab) => {
    ;(tab.floorSummaryList || []).forEach((f) => floorSummaries.push(f))
  })

  return {
    patrolId: resp.patrolId,
    patrolDate: resp.patrolDate,
    shift: SHIFT_CODE_TO_KEY[resp.shift || 0],
    inspector: resp.inspector,
    inspectorName: resp.inspectorName,
    inspectorNameAr: resp.inspectorNameAr,
    contractorName: resp.reportedByName,
    contractorNameAr: resp.reportedByNameAr,
    status: statusFallback,
    currentAnswers: resp.patrolAnswerList || [],
    code: resp.code,
    tabSummaries,
    floorSummaries,
  }
}

const buildCategories = (
  answers: SecurityPatrolAnswerDto[],
): PatrolChecklistCategoryViewData[] => {
  const categoryMap = new Map<string, PatrolChecklistCategoryViewData>()

  answers.forEach((answer) => {
    const categoryKey = String(answer.sectionId ?? 'unsectioned')
    let category = categoryMap.get(categoryKey)
    if (!category) {
      category = {
        id: categoryKey,
        sectionId: answer.sectionId,
        sectionName: answer.sectionName,
        sectionNameAr: answer.sectionNameAr,
        defaultOpen: categoryMap.size === 0,
        items: [],
      }
      categoryMap.set(categoryKey, category)
    }

    category.items.push({
      id: String(answer.patrolAnswerId),
      itemId: answer.itemId,
      itemName: answer.itemName,
      itemNameAr: answer.itemNameAr,
      answer: IS_SITUATION_TO_ANSWER[answer.isSituation ?? -1] || 'na',
      findings: answer.findings || [],
    })
  })

  return Array.from(categoryMap.values())
}

const getStatusFromParam = (
  value?: string,
): SecurityPatrolStatus | undefined =>
  value === 'draft' ||
  value === 'underReview' ||
  value === 'approved' ||
  value === 'rejected'
    ? value
    : undefined

const StatusBadge = ({ status }: { status: SecurityPatrolStatus }) => {
  const { t } = useTranslation(['securityPatrol'])

  return (
    <Badge
      className={`${classPrefix}__status ${classPrefix}__status--${status}`}
      color={statusColorMap[status]}
      text={t(`securityPatrol:status.${status}`)}
    />
  )
}

const HeaderTitle = ({ status }: { status: SecurityPatrolStatus }) => (
  <HeaderTitleContent status={status} />
)

const HeaderTitleContent = ({ status }: { status: SecurityPatrolStatus }) => {
  const { t } = useTranslation(['securityPatrol'])

  return (
    <div className={`${classPrefix}__page-title`}>
      <span>{t('securityPatrol:patrolRecords.detail.titleUpper')}</span>
      <StatusBadge status={status} />
    </div>
  )
}

const AnswerBadge = ({ answer }: { answer: SecurityPatrolAnswer }) => {
  const { t } = useTranslation(['common'])
  const text = answer === 'na' ? 'N/A' : t(`common:${answer}`)

  return (
    <span
      className={`${classPrefix}__answer ${classPrefix}__answer--${answer}`}
    >
      {text}
    </span>
  )
}

const AttachmentThumbs = ({
  attachments = [],
}: {
  attachments?: SecurityPatrolAttachment[]
}) => {
  const [previewImage, setPreviewImage] = useState<PreviewImage | null>(null)

  if (!attachments.length) {
    return <div className={`${classPrefix}__field-value`}>-</div>
  }

  return (
    <>
      <div className={`${classPrefix}__thumbs`}>
        {attachments.map((attachment, index) => {
          const key =
            attachment.id ||
            attachment.attachmentId ||
            attachment.uniqueId ||
            index

          return (
            <AttachmentThumb
              key={key}
              attachment={attachment}
              index={index}
              onPreview={setPreviewImage}
            />
          )
        })}
      </div>
      <Modal
        title={previewImage?.fileName}
        visible={Boolean(previewImage)}
        footer={null}
        className={`${classPrefix}__preview-modal`}
        style={{ width: 'auto' }}
        onCancel={() => setPreviewImage(null)}
        unmountOnExit
      >
        {previewImage ? (
          <div className={`${classPrefix}__preview`}>
            <img
              src={previewImage.url}
              alt={previewImage.fileName}
              className={`${classPrefix}__preview-img`}
            />
          </div>
        ) : null}
      </Modal>
    </>
  )
}

const AttachmentThumb = ({
  attachment,
  index,
  onPreview,
}: {
  attachment: SecurityPatrolAttachment
  index: number
  onPreview: (preview: PreviewImage) => void
}) => {
  const [previewUrl, setPreviewUrl] = useState('')
  const requestUrl = attachment.url || attachment.absUrl || ''
  const fileType = attachment.fileType || attachment.contentType

  useEffect(() => {
    let canceled = false
    let objectUrl = ''

    setPreviewUrl('')

    const loadPreview = async () => {
      if (!requestUrl) return

      try {
        const response: any = await downloadFileByUrl(
          requestUrl,
          attachment.fileName,
          fileType,
        )
        const blobData = response?.data
        if (!blobData) return

        const contentType = response?.headers?.['content-type']
        const blob =
          blobData instanceof Blob
            ? blobData
            : new Blob([blobData], { type: contentType })

        objectUrl = URL.createObjectURL(blob)
        if (canceled) {
          URL.revokeObjectURL(objectUrl)
          return
        }

        setPreviewUrl(objectUrl)
      } catch {
        setPreviewUrl('')
      }
    }

    void loadPreview()

    return () => {
      canceled = true
      if (objectUrl) {
        URL.revokeObjectURL(objectUrl)
      }
    }
  }, [attachment.fileName, fileType, requestUrl])

  if (!previewUrl) {
    return (
      <span
        title={attachment.fileName}
        className={`${classPrefix}__thumb ${classPrefix}__thumb--${
          (index % 3) + 1
        }`}
      />
    )
  }

  return (
    <button
      type='button'
      title={attachment.fileName}
      className={`${classPrefix}__thumb ${classPrefix}__thumb--image`}
      onClick={() =>
        onPreview({
          url: previewUrl,
          fileName: attachment.fileName,
        })
      }
    >
      <img src={previewUrl} alt={attachment.fileName || ''} />
    </button>
  )
}

const FindingCard = ({
  finding,
  index,
}: {
  finding: SecurityPatrolFindingDto
  index: number
}) => {
  const { t } = useTranslation(['securityPatrol'])

  return (
    <div className={`${classPrefix}__finding`}>
      <div className={`${classPrefix}__finding-title`}>
        {t('securityPatrol:patrolRecords.detail.finding', { n: index + 1 })}
      </div>
      <div className={`${classPrefix}__finding-block`}>
        <div className={`${classPrefix}__field-label`}>
          {t('securityPatrol:patrolRecords.detail.notes')}
        </div>
        <div className={`${classPrefix}__field-value`}>
          {safeFieldText(finding.findingRemark, finding.findingRemarkAr)}
        </div>
      </div>
      <div className={`${classPrefix}__finding-block`}>
        <div className={`${classPrefix}__field-label`}>
          {t('securityPatrol:patrolRecords.detail.attachment')}
        </div>
        <AttachmentThumbs attachments={finding.attachmentList || []} />
      </div>
      <div className={`${classPrefix}__finding-block`}>
        <div className={`${classPrefix}__field-label`}>
          {t('securityPatrol:patrolRecords.detail.correctiveActions')}
        </div>
        <div className={`${classPrefix}__field-value`}>
          {safeFieldText(finding.correctiveAction, finding.correctiveActionAr)}
        </div>
      </div>
      <div className={`${classPrefix}__finding-row`}>
        <div>
          <div className={`${classPrefix}__field-label`}>
            {t('securityPatrol:patrolRecords.detail.responsibleDepartment')}
          </div>
          <div className={`${classPrefix}__field-value`}>
            {safeFieldText(finding.org?.orgName, finding.org?.orgNameAr)}
          </div>
        </div>
        <div>
          <div className={`${classPrefix}__field-label`}>
            {t('securityPatrol:patrolRecords.detail.targetClosureDate')}
          </div>
          <div className={`${classPrefix}__field-value`}>
            {formatDisplayDate(finding.targetClosureDate)}
          </div>
        </div>
      </div>
    </div>
  )
}

const ChecklistItemView = ({ item }: { item: PatrolChecklistItemViewData }) => (
  <div className={`${classPrefix}__item`}>
    <div className={`${classPrefix}__item-head`}>
      <div className={`${classPrefix}__question`}>
        {safeFieldText(item.itemName, item.itemNameAr)}
      </div>
      <AnswerBadge answer={item.answer} />
    </div>
    {item.answer === 'no' && item.findings?.length ? (
      <div className={`${classPrefix}__findings-card`}>
        {item.findings.map((finding, index) => (
          <FindingCard
            key={finding.correctiveActionId || index}
            finding={finding}
            index={index}
          />
        ))}
      </div>
    ) : null}
  </div>
)

const CategorySection = ({
  category,
  index,
}: {
  category: PatrolChecklistCategoryViewData
  index: number
}) => {
  const { t } = useTranslation(['securityPatrol', 'common'])
  const [open, setOpen] = useState(category.defaultOpen ?? false)

  return (
    <div className={`${classPrefix}__category`}>
      <div
        className={`${classPrefix}__category-head`}
        onClick={() => setOpen((value) => !value)}
      >
        <div>
          <div className={`${classPrefix}__category-label`}>
            {t('securityPatrol:patrolRecords.detail.category', {
              n: index + 1,
            })}
          </div>
          <div className={`${classPrefix}__category-title`}>
            {safeFieldText(category.sectionName, category.sectionNameAr) ||
              t('common:noData')}
          </div>
        </div>
        {open ? <IconUp /> : <IconDown />}
      </div>
      {open && (
        <div className={`${classPrefix}__category-body`}>
          {category.items.map((item) => (
            <ChecklistItemView key={item.id} item={item} />
          ))}
        </div>
      )}
    </div>
  )
}

const PatrolRecordDetail = () => {
  const { t } = useTranslation(['securityPatrol', 'common'])
  const navigate = useNavigate()
  const { patrolRecordId, status: statusParam } = useParams<{
    patrolRecordId: string
    status: string
  }>()
  const [detail, setDetail] = useState<PatrolDetailViewData | null>(null)
  const [approveLog, setApproveLog] = useState<SecurityPatrolApprovalRecord[]>(
    [],
  )
  const [approveFlag, setApproveFlag] = useState(0)
  const backUrl = `/security-patrol/patrol-records`

  const [selectFloor, setSelectFloor] = useState<string>('around')
  const { loading: detailLoading, runAsync: runPatrolDetail } = useRequest(
    getSecurityPatrolDetailRequest,
    {
      manual: true,
    },
  )
  const { runAsync: runPatrolFindingCount } = useRequest(
    getPatrolFindingCountRequest,
    {
      manual: true,
    },
  )
  const { loading: approveDetailLoading, runAsync: runPatrolApproveDetail } =
    useRequest(getSecurityPatrolApproveDetailRequest, {
      manual: true,
    })
  const currentStatus =
    detail?.status || getStatusFromParam(statusParam) || 'draft'

  const breadcrumbRoutes = useMemo(
    () => [
      {
        path: '/security-patrol/patrol-records',
        breadcrumbName: t('securityPatrol:menu.patrolRecords'),
      },
      {
        path: '#',
        breadcrumbName: t('securityPatrol:patrolRecords.detail.title'),
      },
    ],
    [t],
  )
  // 详情按 tab+floor 拉取；finding/count 单独拉取一次
  const [tabSummaries, setTabSummaries] = useState<
    PatrolTabSummaryResponseItem[]
  >([])

  // Nav data built from tabSummaries (finding count API), independent of per-floor detail
  const navData = useMemo(() => {
    const tabIssueMap = new Map<number, number>()
    const floorIssueMap = new Map<string, number>()
    ;(tabSummaries ?? []).forEach((tab) => {
      tabIssueMap.set(tab.type, tab.findingCount ?? 0)
      ;(tab.floorSummaryList ?? []).forEach((f) => {
        floorIssueMap.set(`${f.type}-${f.floorCode}`, f.findingCount ?? 0)
      })
    })
    return {
      around: { issueCount: tabIssueMap.get(1) ?? 0 },
      inside: {
        issueCount: tabIssueMap.get(2) ?? 0,
        floors: [
          { key: 'inside-0', label: t('securityPatrol:patrolRecords.detail.tabs.floor', { unit: 'G' }), issueCount: floorIssueMap.get('2-0') ?? 0 },
          { key: 'inside-1', label: t('securityPatrol:patrolRecords.detail.tabs.floor', { unit: 'M' }), issueCount: floorIssueMap.get('2-1') ?? 0 },
          { key: 'inside-2', label: t('securityPatrol:patrolRecords.detail.tabs.floor', { unit: '1' }), issueCount: floorIssueMap.get('2-2') ?? 0 },
          { key: 'inside-3', label: t('securityPatrol:patrolRecords.detail.tabs.floor', { unit: '2' }), issueCount: floorIssueMap.get('2-3') ?? 0 },
          { key: 'inside-4', label: t('securityPatrol:patrolRecords.detail.tabs.floor', { unit: '3' }), issueCount: floorIssueMap.get('2-4') ?? 0 },
          { key: 'inside-5', label: t('securityPatrol:patrolRecords.detail.tabs.floor', { unit: '4' }), issueCount: floorIssueMap.get('2-5') ?? 0 },
          { key: 'inside-6', label: t('securityPatrol:patrolRecords.detail.tabs.floor', { unit: '5' }), issueCount: floorIssueMap.get('2-6') ?? 0 },
          { key: 'inside-7', label: t('securityPatrol:patrolRecords.detail.tabs.floor', { unit: '6' }), issueCount: floorIssueMap.get('2-7') ?? 0 },
          { key: 'inside-8', label: t('securityPatrol:patrolRecords.detail.tabs.floor', { unit: 'RF' }), issueCount: floorIssueMap.get('2-8') ?? 0 },
        ],
      },
      parking: {
        issueCount: tabIssueMap.get(3) ?? 0,
        floors: [
          { key: 'parking-9',  label: 'P1', issueCount: floorIssueMap.get('3-9')  ?? 0 },
          { key: 'parking-10', label: 'P2', issueCount: floorIssueMap.get('3-10') ?? 0 },
          { key: 'parking-11', label: 'P3', issueCount: floorIssueMap.get('3-11') ?? 0 },
        ],
      },
    }
  }, [tabSummaries, t])

  const currentCategories = useMemo(() => {
    if (!detail) return []
    return buildCategories(detail.currentAnswers || [])
  }, [detail])

  const fetchApproveDetail = useCallback(async () => {
    if (!patrolRecordId) return
    try {
      const res = (await runPatrolApproveDetail({
        patrolId: patrolRecordId,
      })) as PatrolApproveDetailResponse
      setApproveLog(res?.approveList || [])
      setApproveFlag(res?.approveFlag || 0)
    } catch {
      setApproveLog([])
      setApproveFlag(0)
    }
  }, [patrolRecordId, runPatrolApproveDetail])


  // 首次进入：拉 finding/count 汇总 + 审批详情
  useEffect(() => {
    if (!patrolRecordId) return
    const init = async () => {
      try {
        const summaries = (await runPatrolFindingCount({
          patrolId: patrolRecordId,
        })) as PatrolTabSummaryResponseItem[]
        setTabSummaries(summaries || [])
      } catch {
        setTabSummaries([])
      }
    }
    void init()
    void fetchApproveDetail()
  }, [patrolRecordId, runPatrolFindingCount, fetchApproveDetail])

  // 切换 tab/floor：按 type+floor 重新拉取 detail
  useEffect(() => {
    if (!patrolRecordId) return
    const { type, floor } = resolveTypeAndFloorCode(selectFloor)
    const fetchDetail = async () => {
      try {
        const res = (await runPatrolDetail({
          patrolId: patrolRecordId,
          type,
          floor,
        })) as PatrolDetailResponse
        const fallback = getStatusFromParam(statusParam) || 'draft'
        setDetail(mapDetailResponse(res, fallback, tabSummaries))
      } catch {
        setDetail(null)
      }
    }
    void fetchDetail()
  }, [patrolRecordId, runPatrolDetail, selectFloor, statusParam, tabSummaries])

  const handleBack = () => {
    navigate('/security-patrol/patrol-records')
  }

  return (
    <PageWrapper
      showBreadcrumb
      routes={breadcrumbRoutes}
      resetMarginTop
      headerTitle={<HeaderTitle status={currentStatus} />}
      pageClassName={`${classPrefix}-page`}
    >
      <Spin
        className={`${classPrefix}__spin`}
        loading={detailLoading || approveDetailLoading}
        style={{ width: '100%' }}
      >
        <div className={classPrefix}>
          <div className={`${classPrefix}__layout`}>
            <div className={`${classPrefix}__main`}>
              <div className={`${classPrefix}__meta`}>
                <div className={`${classPrefix}__meta-item`}>
                  <div className={`${classPrefix}__meta-label`}>
                    {t('securityPatrol:patrolRecords.detail.patrolId')}
                  </div>
                  <div className={`${classPrefix}__meta-value`}>
                    {detail?.code || '-'}
                  </div>
                </div>
                <div className={`${classPrefix}__meta-item`}>
                  <div className={`${classPrefix}__meta-label`}>
                    {t('securityPatrol:patrolRecords.detail.patrolDate')}
                  </div>
                  <div className={`${classPrefix}__meta-value`}>
                    {detail?.patrolDate || '-'}
                  </div>
                </div>
                <div className={`${classPrefix}__meta-item`}>
                  <div className={`${classPrefix}__meta-label`}>
                    {t('securityPatrol:patrolRecords.columns.shift')}
                  </div>
                  <div className={`${classPrefix}__meta-value`}>
                    {detail?.shift
                      ? t(`securityPatrol:shift.${detail.shift}`)
                      : '-'}
                  </div>
                </div>
                <div className={`${classPrefix}__meta-item`}>
                  <div className={`${classPrefix}__meta-label`}>
                    {t('securityPatrol:patrolRecords.columns.contractor')}
                  </div>
                  <div className={`${classPrefix}__meta-value`}>
                    {renderEllipsisText(
                      safeFieldText(
                        detail?.contractorName,
                        detail?.contractorNameAr,
                      ),
                    )}
                  </div>
                </div>
                <div className={`${classPrefix}__meta-item`}>
                  <div className={`${classPrefix}__meta-label`}>
                    {t('securityPatrol:patrolRecords.detail.patrollerName')}
                  </div>
                  <div className={`${classPrefix}__meta-value`}>
                    {renderEllipsisText(
                      detail?.inspector ? detail.inspector : '-',
                    )}
                  </div>
                </div>
              </div>

              <div className={`${classPrefix}__main-content`}>
                <div className={`${classPrefix}__main-content-tabs`}>
                  {/* Around the Building */}
                  <div
                    className={classNames(
                      `${classPrefix}__main-content-tabs-item`,
                      { select: selectFloor === 'around' },
                    )}
                    onClick={() => setSelectFloor('around')}
                  >
                    <div className={`${classPrefix}__main-content-tabs-item-title`}>
                      {t('securityPatrol:patrolRecords.detail.tabs.around')}
                    </div>
                    {!!navData.around.issueCount && (
                      <div className={`${classPrefix}__main-content-tabs-item-issueCount`}>
                        {navData.around.issueCount}
                      </div>
                    )}
                  </div>

                  {/* Inside the Building group header */}
                  <div
                    className={`${classPrefix}__main-content-tabs-item`}
                    onClick={() => setSelectFloor('inside-0')}
                  >
                    <div className={`${classPrefix}__main-content-tabs-item-title`}>
                      {t('securityPatrol:patrolRecords.detail.tabs.inside')}
                    </div>
                    {!!navData.inside.issueCount && (
                      <div className={`${classPrefix}__main-content-tabs-item-issueCount`}>
                        {navData.inside.issueCount}
                      </div>
                    )}
                  </div>
                  {navData.inside.floors.map((floor) => (
                    <div
                      key={floor.key}
                      className={classNames(
                        `${classPrefix}__main-content-tabs-item`,
                        'second-level',
                        { select: selectFloor === floor.key },
                      )}
                      onClick={() => setSelectFloor(floor.key)}
                    >
                      <div className={`${classPrefix}__main-content-tabs-item-title`}>
                        {floor.label}
                      </div>
                      {!!floor.issueCount && (
                        <div className={`${classPrefix}__main-content-tabs-item-issueCount`}>
                          {floor.issueCount}
                        </div>
                      )}
                    </div>
                  ))}

                  {/* Parking group header */}
                  <div
                    className={`${classPrefix}__main-content-tabs-item`}
                    onClick={() => setSelectFloor('parking-9')}
                  >
                    <div className={`${classPrefix}__main-content-tabs-item-title`}>
                      {t('securityPatrol:patrolRecords.detail.tabs.parking')}
                    </div>
                    {!!navData.parking.issueCount && (
                      <div className={`${classPrefix}__main-content-tabs-item-issueCount`}>
                        {navData.parking.issueCount}
                      </div>
                    )}
                  </div>
                  {navData.parking.floors.map((floor) => (
                    <div
                      key={floor.key}
                      className={classNames(
                        `${classPrefix}__main-content-tabs-item`,
                        'second-level',
                        { select: selectFloor === floor.key },
                      )}
                      onClick={() => setSelectFloor(floor.key)}
                    >
                      <div className={`${classPrefix}__main-content-tabs-item-title`}>
                        {floor.label}
                      </div>
                      {!!floor.issueCount && (
                        <div className={`${classPrefix}__main-content-tabs-item-issueCount`}>
                          {floor.issueCount}
                        </div>
                      )}
                    </div>
                  ))}
                </div>

                <div className={`${classPrefix}__categories`}>
                  {currentCategories.map((category, index) => (
                    <CategorySection
                      key={`${category.id}`}
                      category={category}
                      index={index}
                    />
                  ))}
                  {!currentCategories.length && (
                    <div className={`${classPrefix}__empty`}>
                      <NoData />
                    </div>
                  )}
                </div>
              </div>
            </div>

            <div className={`${classPrefix}__side`}>
              <ApprovalProgressCard
                title={t('securityPatrol:patrolRecords.detail.reviewTitle')}
                approvalRejected={rejectSecurityPatrolRequest}
                approvalApproved={approveSecurityPatrolRequest}
                approveLog={approveLog}
                approveFlag={approveFlag}
                backUrl={backUrl}
                moduleId={patrolRecordId}
                moduleIdKey='patrolId'
                submittedCardRows={[
                  {
                    label: t('securityPatrol:patrolRecords.detail.contractor'),
                    value:
                      handelFieldNameShow(
                        detail?.contractorName || '',
                        detail?.contractorNameAr || '',
                      ) || '-',
                  },
                  {
                    label: t('securityPatrol:patrolRecords.detail.patroller'),
                    value: detail?.inspector ? detail.inspector : '-',
                  },
                ]}
              />
            </div>
          </div>
        </div>
      </Spin>
      {!detail && !detailLoading && (
        <div className={`${classPrefix}__footer`}>
          <Space size={12}>
            <Button icon={<IconArrowLeft />} onClick={handleBack}>
              {t('common:btn.back')}
            </Button>
          </Space>
        </div>
      )}
    </PageWrapper>
  )
}

