import type { ReactNode } from 'react'
import { Timeline, Form, Input, Button, Message, Avatar } from '@arco-design/web-react'
import {
  IconArrowLeft,
  IconCheckCircle,
  IconCloseCircle,
} from '@arco-design/web-react/icon'
import classNames from 'classnames'
import { useTranslation } from 'react-i18next'
import { useRequest } from 'ahooks'
import { useNavigate } from 'react-router-dom'
import {
  CanApproveEnum,
  approvalResultEnum,
} from '@/constants/monthlyInspection'
import './index.less'
import _ from 'lodash'
import { handelFieldNameShow } from '@/utils/tools'
import UserHead from '../UserHead'
import { getLanguage } from '@common/utils/localStorage'
import { LanguageEnum } from '@common/constants/language'
import { useIsHSEManager } from '@common/hooks/useIsAdmin'
const FormItem = Form.Item
const TimelineItem = Timeline.Item
const classPrefix = 'approval-progress-card'

interface ApprovalProgressCardProps {
  title: string
  className?: string
  approvalRejected?: any
  approvalApproved?: any
  type?: string
  backUrl?: string
  moduleId: string // ID of the approvable module
  moduleIdKey: string // Key of the module ID, defaults to 'monthlyInspectionId'
  approveLog: any
  approveFlag: number
  /** Custom rows for the Submitted node, replacing the default "Submitted by + avatar". */
  submittedCardRows?: Array<{ label: ReactNode; value: ReactNode }>
  /** Pending approvers shown on the H&S Manager Approval step when approveLog is empty. */
  pendingApprovers?: Array<{ id?: string; userName?: string; userNameAr?: string }>
}

const AVATAR_COLORS = ['#EE3EC9', '#7B5EA7', '#3B82F6', '#10B981', '#F59E0B']

const ApprovalProgressCard = ({
  title,
  className,
  approvalRejected,
  approvalApproved,
  approveLog,
  approveFlag = 0, // 0 = no action buttons, 1 = show action buttons
  backUrl,
  moduleId,
  moduleIdKey = 'monthlyInspectionId',
  submittedCardRows,
  pendingApprovers,
}: ApprovalProgressCardProps) => {
  const { t } = useTranslation(['common', 'monthlyInspection'])
  const [form] = Form.useForm()
  const navigate = useNavigate()
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  // const isHSEManager = false
  const isHSEManager = useIsHSEManager()

  const { run: runRejected, loading: runRejectedLoading } = useRequest(
    approvalRejected,
    {
      manual: true,
      onSuccess: () => {
        Message.success(t('common:message.rejectSuccessfully'))
        navigate(backUrl)
      },
    },
  )
  const { run: runApproved, loading: runApprovedLoading } = useRequest(
    approvalApproved,
    {
      manual: true,
      onSuccess: () => {
        Message.success(t('common:message.approveSuccessfully'))
        navigate(backUrl)
      },
    },
  )

  const handelApproval = (approvalType) => {
    const data = form.getFieldsValue()
    if (approvalType === 'reject') {
      runRejected({ [moduleIdKey]: moduleId, comments: data.comment })
    } else {
      runApproved({ [moduleIdKey]: moduleId, comments: data.comment })
    }
  }

  const handelBack = () => {
    navigate(backUrl)
  }

  const paddingApproveStatus = {
    0: t('monthlyInspection:timeLine.Submitted'),
    1: t('monthlyInspection:timeLine.hsManagerApproval'),
    2: t('monthlyInspection:timeLine.incidentReported'),
  }

  const ApproveResult = {
    0: t('monthlyInspection:timeLine.rejected'),
    1: t('monthlyInspection:timeLine.approved'),
  }

  return (
    <div className={classNames(classPrefix, className)}>
      <div className={`${classPrefix}__header`}>{title}</div>
      <div className={`${classPrefix}__content`}>
        <Timeline mode={isLanguageAR ? 'right' : 'left'}>
          {approveLog.length === 0 && (
            <TimelineItem
              className={`${classPrefix}__timeline-item`}
              dot={
                <span
                  className={classNames(`${classPrefix}__dot`, 'active')}
                />
              }
            >
              <div className={`${classPrefix}__item-title`}>
                <span className={`${classPrefix}__item-name`}>
                  {t('monthlyInspection:timeLine.reportSubmission')}
                </span>
              </div>
              <div className={`${classPrefix}__item-card`}>
                <span className={`${classPrefix}__pending`}>
                  {t('monthlyInspection:timeLine.awaitingSubmission')}
                </span>
              </div>
            </TimelineItem>
          )}
          {approveLog.length === 0 && (
            <TimelineItem
              className={`${classPrefix}__timeline-item`}
              dot={<span className={`${classPrefix}__dot`} />}
            >
              {pendingApprovers && pendingApprovers.length > 0 && (
                <div className={`${classPrefix}__pending-avatars`}>
                  {pendingApprovers.map((approver, idx) => {
                    const name = isLanguageAR
                      ? approver.userNameAr || approver.userName
                      : approver.userName || approver.userNameAr
                    return (
                      <Avatar
                        key={approver.id ?? idx}
                        size={28}
                        style={{
                          backgroundColor:
                            AVATAR_COLORS[idx % AVATAR_COLORS.length],
                        }}
                      >
                        {name?.charAt(0) ?? '?'}
                      </Avatar>
                    )
                  })}
                </div>
              )}
              <div className={`${classPrefix}__item-title`}>
                <span className={`${classPrefix}__item-name`}>
                  {t('monthlyInspection:timeLine.hsManagerApproval')}
                </span>
              </div>
            </TimelineItem>
          )}
          {approveLog.map((item, index) => {
            console.log('item', item)
            const actorLabel = paddingApproveStatus[item?.approveStatus]
            const actionName =
              item?.approveStatus === 0
                ? t('monthlyInspection:timeLine.Submitted')
                : !_.isNull(item.approvalResult)
                  ? t('monthlyInspection:timeLine.approvedBy')
                  : t('monthlyInspection:timeLine.waitForApproval')
            const hasOperator =
              !!item.operTime && (!!item.operUserName || !!item.operUserNameAr)
            const isLast =
              index === approveLog.length - 1 && _.isEmpty(item.operTime)
            return (
              <TimelineItem
                key={item.id}
                className={`${classPrefix}__timeline-item`}
                dot={
                  <span
                    className={classNames(`${classPrefix}__dot`, {
                      active: isLast,
                    })}
                  />
                }
              >
                <div className={`${classPrefix}__item-title`}>
                  <span className={`${classPrefix}__item-name`}>
                    {actorLabel}
                  </span>
                  {item.operTime && (
                    <span className={`${classPrefix}__item-time`}>
                      {item.operTime}
                    </span>
                  )}
                </div>

                <div className={`${classPrefix}__item-card`}>
                  {item?.approveStatus === 0 &&
                  submittedCardRows &&
                  submittedCardRows.length > 0 ? (
                    // Custom Submitted card (e.g. Patrol's Contractor / Patroller rows)
                    submittedCardRows.map((row, rowIndex) => (
                      <div key={rowIndex} className={`${classPrefix}__row`}>
                        <span className={`${classPrefix}__row-label`}>
                          {row.label}
                        </span>
                        <span className={`${classPrefix}__row-value`}>
                          {row.value}
                        </span>
                      </div>
                    ))
                  ) : (
                    <>
                      {!_.isNull(item.approvalResult) && (
                        <span
                          className={classNames(
                            `${classPrefix}__status`,
                            `${classPrefix}__status--${
                              item.approvalResult ===
                              approvalResultEnum.ApproveOk
                                ? 2
                                : 1
                            }`,
                          )}
                        >
                          <span className={`${classPrefix}__status-dot`} />
                          {ApproveResult[item.approvalResult]}
                        </span>
                      )}
                      <div className={`${classPrefix}__row`}>
                        <span className={`${classPrefix}__row-label`}>
                          {item?.approveStatus == 2
                            ? t('monthlyInspection:timeLine.reportedBy')
                            : actionName}
                        </span>
                        {hasOperator && (
                          <span className={`${classPrefix}__person`}>
                            <UserHead size={20} />
                            <span>
                              {handelFieldNameShow(
                                item.operUserName,
                                item.operUserNameAr,
                              )}
                            </span>
                          </span>
                        )}
                      </div>
                      {item.comments && (
                        <div className={`${classPrefix}__row`}>
                          <span className={`${classPrefix}__row-label`}>
                            {`${t('monthlyInspection:timeLine.comments')}:`}
                          </span>
                          <span className={`${classPrefix}__row-value`}>
                            {item.comments}
                          </span>
                        </div>
                      )}
                    </>
                  )}
                </div>
              </TimelineItem>
            )
          })}
        </Timeline>
      </div>

      {approveFlag === CanApproveEnum.CanApprove && (
        <div className={`${classPrefix}__footer`}>
          {isHSEManager && (
            <Form layout='vertical' form={form}>
              <FormItem
                label={t('monthlyInspection:timeLine.comment')}
                field={'comment'}
                className={`${classPrefix}__comment-form-item`}
              >
                <Input.TextArea
                  placeholder={t('common:pleaseEnter')}
                  maxLength={500}
                  showWordLimit
                  className={`${classPrefix}__comment-input`}
                />
              </FormItem>
            </Form>
          )}
          <div className={`${classPrefix}__footer-actions`}>
            <Button onClick={() => handelBack()}>
              <IconArrowLeft className='icon-left' />
              <span>{t('common:btn.back')}</span>
            </Button>
            {isHSEManager && (
              <>
                <Button
                  status='danger'
                  onClick={() => handelApproval('reject')}
                  loading={runRejectedLoading}
                  icon={<IconCloseCircle />}
                >
                  <span>{t('common:btn.reject')}</span>
                </Button>
                <Button
                  type='primary'
                  onClick={() => handelApproval('approve')}
                  loading={runApprovedLoading}
                  icon={<IconCheckCircle />}
                >
                  <span>{t('common:btn.approve')}</span>
                </Button>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  )
}

export default ApprovalProgressCard

